    INPUT_NONE = 0,
    INPUT_PRESSURE,
    INPUT_DOOR_OPEN,
    INPUT_DOOR_CLOSED,
    INPUT_SENSOR_TIMEOUT,
    INPUT_INVALID_PRESSURE,
    INPUT_INVALID_DOOR,
} controller_input_kind_t;

// Input structure - internal types used by uart_transport.c
typedef struct {
    controller_input_kind_t kind;
    int pressure_kpa;
    bool door_closed;
    uint32_t now_ms;
} controller_input_t;

// Controller state structure
typedef struct {
    bool compressor_on;
    bool vent_open;
    controller_state_t state;
    bool has_valid_pressure;
    int last_pressure_kpa;
    uint32_t last_pressure_ms;
    bool has_valid_door;
    bool door_closed;
    uint32_t last_door_ms;
} controller_t;

